#include <bits/stdc++.h>
using namespace std;
double a,b,a1,b1;
int main(){
	int n,k;
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		if(i%k==0){
			a1++;
			a+=i;
		}else{
			b1++;
			b+=i;
		}
	}
	cout<<fixed<<setprecision(1)<<a/a1<<" "<<fixed<<setprecision(1)<<b/b1;
	return 0;
}
